--
-- Table structure for table `itens_operacionais`
--

DROP TABLE IF EXISTS `itens_operacionais`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `itens_operacionais` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `apartamento_id` int unsigned NOT NULL,
  `nome` varchar(150) NOT NULL,
  `categoria` varchar(80) DEFAULT NULL,
  `quantidade` int unsigned NOT NULL DEFAULT '1',
  `status_item` enum('BOM','ATENCAO','PROBLEMA','EM_FALTA') NOT NULL DEFAULT 'BOM',
  `observacao` text,
  `imagem` varchar(255) DEFAULT NULL,
  `updated_by` int unsigned DEFAULT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`id`),
  KEY `apartamento_id` (`apartamento_id`),
  KEY `updated_by` (`updated_by`),
  CONSTRAINT `itens_operacionais_ibfk_1` FOREIGN KEY (`apartamento_id`) REFERENCES `apartamentos` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `itens_operacionais_ibfk_2` FOREIGN KEY (`updated_by`) REFERENCES `usuarios` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=377 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

